    45тЖТexport const pmScheduleRoutes = new Hono<{ Variables: AppVariables }>();
    46тЖТ
    47тЖТ/**
    48тЖТ * GET /pm/schedule
    49тЖТ *
    50тЖТ * List PM schedules with filtering and pagination.
    51тЖТ *
    52тЖТ * Query Parameters:
    53тЖТ * - trainId: Filter by train
    54тЖТ * - depotId: Filter by assigned depot
    55тЖТ * - pmTypeId: Filter by PM type
    56тЖТ * - status: Filter by status (SCHEDULED, IN_PROGRESS, COMPLETED, DEFERRED, CANCELLED)
    57тЖТ * - fromDate: Target date from (inclusive)
    58тЖТ * - toDate: Target date to (inclusive)
    59тЖТ * - scenarioId: Get scenario schedule (null/omitted = production)
    60тЖТ */
    61тЖТpmScheduleRoutes.get('/pm/schedule', async (c) => {
    62тЖТ  // Parse query filters
    63тЖТ  const trainId = c.req.query('trainId');
    64тЖТ  const depotId = c.req.query('depotId');
