    69тЖТ  const scenarioId = c.req.query('scenarioId');
    70тЖТ
    71тЖТ  // Build filter conditions
    72тЖТ  const conditions: SQL<unknown>[] = [];
    73тЖТ
    74тЖТ  if (trainId && isValidUuid(trainId)) {
    75тЖТ    conditions.push(eq(pmSchedule.trainId, trainId));
    76тЖТ  }
