    82тЖТ  }
    83тЖТ  if (status) {
    84тЖТ    const validStatuses = ['SCHEDULED', 'IN_PROGRESS', 'COMPLETED', 'DEFERRED', 'CANCELLED'] as const;
    85тЖТ    if (validStatuses.includes(status as typeof validStatuses[number])) {
    86тЖТ      conditions.push(eq(pmSchedule.status, status as typeof validStatuses[number]));
    87тЖТ    }
    88тЖТ  }
    89тЖТ  if (fromDate) {
    90тЖТ    conditions.push(gte(pmSchedule.targetDate, fromDate));
    91тЖТ  }
