   293тЖТ * - assignedTrackId?: UUID of assigned track
   294тЖТ * - scenarioId?: UUID of scenario (null for production)
   295тЖТ * - reason?: Reason for manual scheduling
   296тЖТ */
   297тЖТpmScheduleRoutes.post('/pm/schedule', async (c) => {
   298тЖТ  const requestId = getRequestId(c);
   299тЖТ  const body = await c.req.json();
   300тЖТ
   301тЖТ  // Validate required fields
   302тЖТ  if (!body.trainId || !isValidUuid(body.trainId)) {
